sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {
    var result = {
        status: "success",
        incident_states: []
    };

    try {
        var labels = [];
        if (request.queryParams.label) {
            for (var i = 0; i < request.queryParams.label.length; i++) {
                var trimmed = String(request.queryParams.label[i]).trim();
                if (trimmed) labels.push(trimmed);
            }
        }

        var limit = 100;
        var excludeSysIds = [];

        if (labels.length > 0) {
            // Query 1: All exact matches for any of the labels
            var exactGR = new GlideRecord('sys_choice');
            exactGR.addQuery('name', 'incident');
            exactGR.addQuery('element', 'state');
            exactGR.addQuery('label', 'IN', labels.join(','));
            exactGR.orderBy('label');
            exactGR.query();

            while (exactGR.next()) {
                excludeSysIds.push(exactGR.sys_id.toString());
                result.incident_states.push({
                    label: exactGR.label.toString(),
                    value: exactGR.value.toString(),
                    sys_id: exactGR.sys_id.toString()
                });
            }

            // Query 2: Fill remaining slots with CONTAINS matches
            var remaining = limit - result.incident_states.length;
            if (remaining > 0) {
                var containsGR = new GlideRecord('sys_choice');
                containsGR.addQuery('name', 'incident');
                containsGR.addQuery('element', 'state');
                var orCondition = containsGR.addQuery('label', 'CONTAINS', labels[0]);
                for (var j = 1; j < labels.length; j++) {
                    orCondition.addOrCondition('label', 'CONTAINS', labels[j]);
                }
                if (excludeSysIds.length > 0) {
                    containsGR.addQuery('sys_id', 'NOT IN', excludeSysIds.join(','));
                }
                containsGR.orderBy('label');
                containsGR.setLimit(remaining);
                containsGR.query();

                while (containsGR.next()) {
                    result.incident_states.push({
                        label: containsGR.label.toString(),
                        value: containsGR.value.toString(),
                        sys_id: containsGR.sys_id.toString()
                    });
                }
            }

        } else {
            var stateGR = new GlideRecord('sys_choice');
            stateGR.addQuery('name', 'incident');
            stateGR.addQuery('element', 'state');
            stateGR.orderBy('label');
            stateGR.setLimit(limit);
            stateGR.query();

            while (stateGR.next()) {
                result.incident_states.push({
                    label: stateGR.label.toString(),
                    value: stateGR.value.toString(),
                    sys_id: stateGR.sys_id.toString()
                });
            }
        }

        response.setStatus(200);
        return result;

    } catch (e) {
        response.setStatus(400);
        return {
            status: "error",
            message: e.message || "Unexpected error occurred while processing the request."
        };
    }

})(request, response);
